def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math
    import re

    evidence = getattr(ctx, "evidence", {}) or {}
    joints = getattr(ctx, "joints", {}) or {}

    feedback = str(
        getattr(ctx, "last_feedback", "")
        or evidence.get("__last_feedback__", "")
        or evidence.get("last_feedback", "")
        or ""
    )
    feedback_l = feedback.lower()

    REV_10 = math.radians(10.0)
    PRI_10 = 0.010

    def norm(v):
        try:
            x, y, z = float(v[0]), float(v[1]), float(v[2])
        except Exception:
            x, y, z = 1.0, 0.0, 0.0
        n = math.sqrt(x * x + y * y + z * z)
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [x / n, y / n, z / n]

    def ev_for(name):
        return evidence.get(name, {}) or {}

    def labels_for(name):
        return " ".join(str(x).lower() for x in (ev_for(name).get("labels") or []))

    def initial_for(name, joint):
        init = ev_for(name).get("initial_estimate") or {}
        return (
            norm(init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))),
            float(init.get("lower", 0.0) or 0.0),
            float(init.get("upper", 0.0) or 0.0),
        )

    def recommended_axis(name, joint):
        ev = ev_for(name)

        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return norm(rec)

        labels = labels_for(name)
        best_axis = None
        best_score = -1.0e100

        for cand in ev.get("axis_candidates") or []:
            aw = cand.get("axis_world")
            if not aw or len(aw) < 3:
                continue

            score = float(cand.get("score", 0.0) or 0.0)
            reason = str(cand.get("reason", "")).lower()

            if joint.get("type") == "prismatic" and any(
                k in labels
                for k in ("drawer", "pan", "tray", "basket", "bin", "pull-out", "pull out")
            ):
                if "outward" in reason or "centroid-outward" in reason:
                    score += 0.25
                if "authored" in reason:
                    score -= 0.05

            if score > best_score:
                best_score = score
                best_axis = aw

        return norm(best_axis if best_axis is not None else joint.get("axis_world", [1.0, 0.0, 0.0]))

    def mentioned(name):
        return name.lower() in feedback_l

    def axis_blocked(name):
        if not mentioned(name):
            return False
        return (
            "qc_joint_axis" in feedback_l
            or "joint axis validation failed" in feedback_l
            or "deviates from" in feedback_l
            or "switch axis" in feedback_l
            or "rotate toward" in feedback_l
        )

    def overlap_blocked(name):
        if not mentioned(name):
            return False
        return (
            "qc_sampled_motion_overlap" in feedback_l
            or "sampled_motion_overlap" in feedback_l
            or "intersects parent/static geometry" in feedback_l
            or "sampled articulation motion intersects" in feedback_l
        )

    def negative_invalid(name):
        if not mentioned(name):
            return False
        return (
            "invalid at q=-" in feedback_l
            or re.search(r"invalid\s+at\s+q\s*=\s*-", feedback_l) is not None
        )

    def endpoint_q(name, endpoint):
        if not mentioned(name):
            return None

        pat = (
            re.escape(name.lower())
            + r"\s*:\s*.{0,500}?"
            + re.escape(endpoint.lower())
            + r"\s+endpoint\s+q\s*=\s*([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)"
        )
        m = re.search(pat, feedback_l, flags=re.DOTALL)
        if not m:
            return None

        try:
            return float(m.group(1))
        except Exception:
            return None

    estimates = []

    for name, joint in sorted(joints.items()):
        joint_type = joint.get("type")
        labels = labels_for(name)
        init_axis, init_lower, init_upper = initial_for(name, joint)

        # Reconstruct the prior Articraft-style candidate from ctx/evidence.
        # Joints not named by the latest blocking feedback are treated as
        # correct and left at this reconstructed prior candidate.
        axis = recommended_axis(name, joint)
        lower = init_lower
        upper = init_upper

        if joint_type == "revolute":
            if "timer" in labels and lower < 0.0:
                lower += REV_10
            elif "temperature" in labels or "temp" in labels or "knob" in labels or "dial" in labels:
                upper += REV_10
        elif joint_type == "prismatic":
            if any(k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")):
                upper += PRI_10

        fb_lower = endpoint_q(name, "lower")
        fb_upper = endpoint_q(name, "upper")
        if fb_lower is not None:
            lower = fb_lower
        if fb_upper is not None:
            upper = fb_upper

        b_axis = axis_blocked(name)
        b_overlap = overlap_blocked(name)
        b_negative = negative_invalid(name)

        state = "need_fix" if (b_axis or b_overlap or b_negative) else "correct"
        axis_action = "unchanged"
        lower_action = "unchanged"
        upper_action = "unchanged"
        confidence = 0.80 if state == "correct" else 0.68

        if b_axis:
            axis = recommended_axis(name, joint)
            axis_action = "changed once by direct switch to the SDK recommended/candidate axis"
            confidence = 0.70

        if joint_type == "revolute" and b_negative:
            lower += REV_10
            lower_action = "changed lower once by +10 degrees, expressed in radians"
            confidence = 0.68

        if joint_type == "prismatic" and b_overlap:
            # Latest blocking signal is authoritative: part_02 still intersects
            # at upper endpoint q=0.04. Take exactly one allowed bounded action
            # this iteration: extend the upper limit by +10 mm from the failed
            # endpoint, producing 0.05 m when q=0.04 was parsed.
            upper += PRI_10
            upper_action = "changed upper once by +10 mm, expressed as +0.010 m"
            confidence = 0.68

        estimates.append(
            LimitEstimate(
                joint_name=name,
                axis_world=norm(axis),
                lower=lower,
                upper=upper,
                confidence=confidence,
                reason=(
                    "State per joint: %s. Latest compile/QC blocking signals: "
                    "axis_blocked=%s, sampled_motion_overlap=%s, negative_endpoint_invalid=%s. "
                    "Parsed endpoint q values from feedback: lower=%s, upper=%s. "
                    "Action this iteration: axis %s; lower %s; upper %s. "
                    "Unblocked joints are marked correct and kept unchanged from the reconstructed "
                    "previous candidate. Bounded action rule respected independently for this joint."
                )
                % (
                    state,
                    b_axis,
                    b_overlap,
                    b_negative,
                    fb_lower,
                    fb_upper,
                    axis_action,
                    lower_action,
                    upper_action,
                ),
            )
        )

    return estimates

