                axis_action = "changed axis once by switching to SDK recommended_axis_world"
                confidence = 0.69

        if joint_type == "prismatic" and b_overlap:
            upper += PRI_10
            upper_action = "changed upper once by +10 mm (+0.010 m) from the failed upper endpoint"
            confidence = min(confidence, 0.69)

        if joint_type == "revolute" and b_negative:
            lower += REV_10
            lower_action = "changed lower once by +10 degrees, expressed in radians"
            confidence = min(confidence, 0.68)

        estimates.append(
            LimitEstimate(
                joint_name=name,
                axis_world=norm(axis),
                lower=lower,
                upper=upper,
                confidence=confidence,
                reason=(
                    "State per joint: %s. Blocking signals parsed for this joint: "
                    "axis_blocked=%s, sampled_motion_overlap=%s, negative_endpoint_invalid=%s. "
                    "Parsed endpoint q from feedback: lower=%s, upper=%s. "
                    "Action this iteration: axis %s; lower %s; upper %s. "
                    "Blocking failures are authoritative and fixed before marking correct. "
                    "This iteration fixes part_00 QC_JOINT_AXIS by one bounded 5-degree "
                    "rotation toward the reported target axis, and fixes part_02 "
                    "QC_SAMPLED_MOTION_OVERLAP at upper q=0.07 by one bounded +10 mm "
                    "upper-limit extension. Joints without blocking feedback stay unchanged."
                )
                % (
                    state,
                    b_axis,
                    b_overlap,
                    b_negative,
                    fb_lower,
                    fb_upper,
                    axis_action,
                    lower_action,
                    upper_action,
                ),
            )
        )

    return estimates
